38590041435887084	/opt/airflow/dags/news_etl.py	2026-06-25 22:00:52.454428+00	from airflow import DAG\nfrom airflow.operators.python import PythonOperator\nfrom datetime import datetime, timedelta\nimport requests\nimport os\nfrom dateutil import parser\nimport urllib.parse\n\nAPI_KEY = os.getenv("NEWS_API_KEY")\nINGESTION_URL = os.getenv("INGESTION_API_URL")\n\nTICKER_MAPPINGS = {\n    "AAPL": "Apple OR AAPL",\n    "MSFT": "Microsoft OR MSFT",\n    "GOOGL": "Google OR Alphabet OR GOOGL",\n    "AMZN": "Amazon OR AMZN",\n    "NVDA": "Nvidia OR NVDA",\n    "META": "Meta OR Facebook OR META",\n    "TSLA": "Tesla OR TSLA",\n    "Bitcoin": "Bitcoin OR BTC",\n    "Ethereum": "Ethereum OR ETH",\n    "SPY": "S&P 500 OR SPY",\n    "QQQ": "Nasdaq OR QQQ",\n    "DIA": "Dow Jones OR DIA",\n    "IWM": "Russell 2000 OR IWM",\n    "GLD": "Gold OR GLD",\n    "TLT": "Treasury Bonds OR TLT"\n}\n\ndefault_args = {\n    "owner": "airflow",\n    "depends_on_past": False,\n    "email_on_failure": False,\n    "email_on_retry": False,\n    "retries": 1,\n    "retry_delay": timedelta(minutes=5),\n}\n\ndef parse_articles(articles_list, ticker):\n    parsed_articles = []\n    for article in articles_list:\n        if not article.get("title") or article.get("title") == "[Removed]":\n            continue\n\n        title = article.get("title", "").strip()\n        desc = article.get("description", "").strip()\n\n        parse = {\n            "title": title,\n            "description": desc,\n            "url": article.get("url"),\n            "publishedAt": article.get("publishedAt"),\n            "matched_tickers": [ticker]\n        }\n        parsed_articles.append(parse)\n    return parsed_articles\n\ndef extract_and_ingest(limit_per_ticker=10):\n    if not API_KEY:\n        raise Exception("missing NEWS_API_KEY in env")\n\n    yesterday = (datetime.now() - timedelta(days=2)).strftime("%Y-%m-%d")\n    domains = "wsj.com,bloomberg.com,reuters.com,cnbc.com,finance.yahoo.com"\n    \n    total_ingested = 0\n    print(f"Fetching {len(TICKER_MAPPINGS)} tickers", flush=True)\n\n    for ticker, search_query in TICKER_MAPPINGS.items():\n        encoded_query = urllib.parse.quote(search_query)\n        url = f"https://newsapi.org/v2/everything?q={encoded_query}&domains={domains}&from={yesterday}&sortBy=publishedAt&pageSize={limit_per_ticker}&apiKey={API_KEY}" \n        print(f'Fetching data for {ticker} (Query: {search_query})', flush=True)\n        try:\n            response = requests.get(url)\n            if response.status_code == 200:\n                raw_articles = response.json().get("articles", [])\n                clean_articles = parse_articles(raw_articles, ticker)\n                print(f"Fetched {len(clean_articles)} articles for {ticker}.", flush=True)\n                \n                for article in clean_articles:\n                    embedd = f"TITLE: {article['title']}. DESCRIPTION: {article['description']}. DATE: {article['publishedAt']}. URL: {article['url']}"\n                    dt = parser.parse(article['publishedAt'])\n                    \n                    payload = {\n                        "text": embedd,\n                        "published_at": dt.timestamp(),\n                        "url": article['url'],\n                        "tickers": article['matched_tickers']\n                    }\n                    \n                    try:\n                        r = requests.post(INGESTION_URL, json=payload)\n                        if r.status_code == 200:\n                            total_ingested += 1\n                    except Exception as e:\n                        print(f"Failed to ingest article for{ticker}: {str(e)}", flush=True)\n            else:\n                print(f"Response error for {ticker}: {response.status_code}", flush=True)\n        except Exception as e:\n            print(f"Error fetching data for{ticker}: {str(e)}", flush=True)\n\n    print(f"Ingestion Process completed. Total items ingested: {total_ingested}", flush=True)\n    try:\n        prune_url = INGESTION_URL.replace("/ingest", "/prune")\n        prune_req = requests.delete(f"{prune_url}?days=30")\n        print(f"ChromaDB pruned: {prune_req.json()}", flush=True)\n    except Exception as e:\n        print(f"Couldnt complete prune process: {str(e)}", flush=True)\n        \n    return f"Pipeline finalizado con éxito. Items cargados: {total_ingested}"\n\nwith DAG(\n    dag_id="daily_financial_news_etl",\n    default_args=default_args,\n    description="Daily ETL pulling financial news individually per ticker and pruning old vectors",\n    schedule="0 6 * * *",\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=["ingestion", "news", "rag"],\n) as dag:\n    \n    ingest_task = PythonOperator(\n        task_id="news_ingest_and_prune",\n        python_callable=extract_and_ingest,\n        op_kwargs={"limit_per_ticker": 10},\n    )
58769700967229370	/opt/airflow/dags/historical_prices_etl.py	2026-06-27 20:20:32.254525+00	from airflow import DAG\nfrom airflow.operators.python import PythonOperator\nfrom datetime import datetime, timedelta\nimport yfinance as yf\nimport pandas as pd\nfrom sqlalchemy import create_engine\nimport os\nfrom airflow.configuration import conf\n\nTICKERS_UNIVERSE = ["SPY", "QQQ", "DIA", "IWM", "GLD", "TLT", "^VIX"]\n\ndefault_args = {\n    "owner": "airflow",\n    "depends_on_past": False,\n    "email_on_failure": False,\n    "email_on_retry": False,\n    "retries": 3,\n    "retry_delay": timedelta(minutes=2),\n}\n\ndef backfill_market_data():\n    """\n    Downloads 5 years of history (OHLCV) and performs a bulk insert into Postgres.\n    Intended to run manually strictly ONCE upon deployment to initialize the database.\n    """\n    db_url = os.getenv("DATABASE_URL")\n    if not db_url:\n        db_url = conf.get('database', 'sql_alchemy_conn')\n\n    if db_url.startswith("postgresql://"):\n        db_url = db_url.replace("postgresql://", "postgresql+psycopg2://")\n\n    engine = create_engine(db_url)\n    \n    print(f"Starting historical download (5 years) for {len(TICKERS_UNIVERSE)} assets...", flush=True)\n\n    df_raw = yf.download(\n        TICKERS_UNIVERSE, \n        period="5y", \n        interval="1d", \n        group_by="ticker", \n        auto_adjust=False\n    )\n    \n    records_to_insert = []\n    \n    for ticker in TICKERS_UNIVERSE:\n        if len(TICKERS_UNIVERSE) == 1:\n            df_ticker = df_raw.copy()\n        else:\n            df_ticker = df_raw[ticker].copy()\n            \n        df_ticker = df_ticker.dropna(subset=['Close'])\n        df_ticker.reset_index(inplace=True)\n        \n        for _, row in df_ticker.iterrows():\n            # Align naming convention to match the daily ETL\n            clean_ticker = "VIX" if ticker == "^VIX" else ticker\n            \n            records_to_insert.append({\n                "ticker": clean_ticker,\n                "date": row['Date'],\n                "open": float(row['Open']),\n                "high": float(row['High']),\n                "low": float(row['Low']),\n                "close": float(row['Close']),\n                "volume": float(row['Volume']),\n                "adj_close": float(row['Adj Close']) if 'Adj Close' in row else float(row['Close'])\n            })\n\n    df_final = pd.DataFrame(records_to_insert)\n    \n    if not df_final.empty:\n        print(f"Inserting {len(df_final)} records into the operational database...", flush=True)\n        \n        # We drop the table and recreate it just in case someone runs the backfill twice by mistake\n        df_final.to_sql("market_data", con=engine, if_exists="replace", index=False)\n        print("Backfill completed successfully. Core systems ready for daily ingestion.", flush=True)\n    else:\n        print("No historical data was found to insert.", flush=True)\n\nwith DAG(\n    dag_id="historical_market_data_backfill",\n    default_args=default_args,\n    description="One-time historical data ingestion (5 years)",\n    schedule=None,  # trigger is strictly manual\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=["ingestion", "historical", "setup"],\n) as dag:\n    \n    backfill_task = PythonOperator(\n        task_id="run_5y_backfill",\n        python_callable=backfill_market_data,\n    )
50617635201209523	/opt/airflow/dags/neuro_inference_etl.py	2026-06-29 18:58:31.125832+00	from airflow.decorators import dag, task\nfrom datetime import datetime, timedelta\nimport sys\nimport logging\n\n# Ensure Airflow can locate the custom quant_engine modules\nsys.path.append("/opt/airflow") \nsys.path.append("/opt/airflow/quant_engine")\n\nfrom quant_engine.neuro_tasks import (\n    reconcile_yesterday_predictions,\n    build_features,\n    run_quant_model,\n    fetch_news_context,\n    evaluate_signals_and_persist\n)   \n\n# Default arguments for the DAG's operational behavior\ndefault_args = {\n    "owner": "quant_team",\n    "depends_on_past": False,\n    "retries": 1,\n    "retry_delay": timedelta(minutes=5),\n}\n\n@dag(\n    dag_id="neuro_trader_production_pipeline",\n    default_args=default_args,\n    description="Operational Neurosymbolic Pipeline with Daily Feedback Loop Reconciliations",\n    schedule="0 22 * * 1-5", # Runs Monday-Friday at 22:00 UTC (Post NY market close)\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=["production", "neurosymbolic", "mlops", "inference"]\n)\ndef neuro_trader_pipeline():\n    """\n    Orchestrates the daily inference cycle.\n    \n    The pipeline is divided into two logical parallel streams:\n    1. Reconciliation: Evaluates the performance of yesterday's predictions against today's closing prices.\n    2. Forward Inference: Extracts today's features, scores them through LightGBM, filters with NLP (FinBERT), \n       evaluates the edge cases via LLM (Gemini), and persists the new targets for tomorrow.\n    """\n\n    @task(task_id="reconcile_yesterday_performance")\n    def task_reconcile(ds=None) -> str:\n        """Triggers the MLOps feedback loop to compute realized returns and drift."""\n        logging.info("Initiating dynamic feedback loop reconciliation against today's EOD prices...")\n        result = reconcile_yesterday_predictions(ds)\n        logging.info(result)\n        return result\n\n    @task(task_id="extract_and_engineer_features")\n    def task_engineer(ds=None) -> list:\n        """Pulls the 300-day rolling window from Postgres and applies cross-sectional feature engineering."""\n        logging.info("Calculating technical and macro features from Postgres panel...")\n        return build_features(ds)\n\n    @task(task_id="quant_model_inference")\n    def task_infer(daily_features: list) -> list:\n        """Scores the latest features using the serialized LightGBM tree and extracts SHAP drivers."""\n        logging.info(f"Running LightGBM inference and SHAP explainability on {len(daily_features)} active tickers...")\n        return run_quant_model(daily_features)\n\n    @task(task_id="semantic_news_retrieval")\n    def task_retrieve(actionable_signals: list, ds) -> list:\n        """Enhances the Quant signals with 48h macroeconomic context and FinBERT sentiment scores."""\n        logging.info(f"Querying ChromaDB for fundamental catalysts on {len(actionable_signals)} candidate signals...")\n        return fetch_news_context(actionable_signals, ds)\n\n    @task(task_id="neurosymbolic_evaluation_and_persistence")\n    def task_evaluate_and_save(enriched_signals: list, ds=None) -> None:\n        """Prompts the LLM with the Neurosymbolic matrix and persists the final veridict to Postgres."""\n        logging.info("Executing Gemini 3.5 Flash evaluations and writing actionable signals to operational database...")\n        evaluate_signals_and_persist(enriched_signals, ds)\n\n    reconciliation_report = task_reconcile()\n    \n    features = task_engineer()\n    raw_signals = task_infer(features)\n    context_signals = task_retrieve(raw_signals)\n    \n    task_evaluate_and_save(context_signals)\n\ndag_instance = neuro_trader_pipeline()
68363485056807876	/opt/airflow/dags/daily_prices_etl.py	2026-06-29 21:24:35.948112+00	from airflow import DAG\nfrom airflow.operators.python import PythonOperator\nfrom datetime import datetime, timedelta\nimport yfinance as yf\nimport pandas as pd\nfrom sqlalchemy import create_engine, text\nimport os\nfrom airflow.configuration import conf\n\nTICKERS_UNIVERSE = ["SPY", "QQQ", "DIA", "IWM", "GLD", "TLT", "^VIX"]\n\ndefault_args = {\n    "owner": "airflow",\n    "depends_on_past": False,\n    "email_on_failure": False,\n    "email_on_retry": False,\n    "retries": 3,\n    "retry_delay": timedelta(minutes=5),\n}\n\n\ndef fetch_daily_market_data():\n    """\n    Download the candle chart for the current day (EOD) and insert it into Postgres.\n    """\n    db_url = os.getenv("DATABASE_URL")\n    if not db_url:\n        db_url = conf.get("database", "sql_alchemy_conn")\n\n    if db_url.startswith("postgresql://"):\n        db_url = db_url.replace("postgresql://", "postgresql+psycopg2://")\n\n    engine = create_engine(db_url)\n\n    print(\n        f"Looking for the day's closing figures for active {len(TICKERS_UNIVERSE)}",\n        flush=True,\n    )\n\n    df_raw = yf.download(\n        TICKERS_UNIVERSE,\n        period="5d",\n        interval="1d",\n        group_by="ticker",\n        auto_adjust=False,\n        threads=False   \n    )\n\n    records_to_insert = []\n\n    for ticker in TICKERS_UNIVERSE:\n        if len(TICKERS_UNIVERSE) == 1:\n            df_ticker = df_raw.copy()\n        else:\n            df_ticker = df_raw[ticker].copy()\n\n        df_ticker = df_ticker.dropna(subset=["Close"])\n        df_ticker.reset_index(inplace=True)\n\n        for _, row in df_ticker.iterrows():\n            clean_ticker = "VIX" if ticker == "^VIX" else ticker\n            records_to_insert.append(\n                {\n                    "ticker": clean_ticker,\n                    "date": row["Date"],\n                    "open": float(row["Open"]),\n                    "high": float(row["High"]),\n                    "low": float(row["Low"]),\n                    "close": float(row["Close"]),\n                    "volume": float(row["Volume"]),\n                    "adj_close": float(row["Adj Close"])\n                    if "Adj Close" in row\n                    else float(row["Close"]),\n                }\n            )\n\n    df = pd.DataFrame(records_to_insert)\n\n    if not df.empty:\n        print("Cleaning up pre-existing records to ensure idempotency", flush=True)\n\n        tickers = tuple(df["ticker"].unique())\n        min_dt = df["date"].min()\n        max_dt = df["date"].max()\n\n        with engine.begin() as conn:\n            delete_query = text("""\n                DELETE FROM market_data \n                WHERE ticker IN :tickers \n                AND date >= :f_min AND date <= :f_max\n            """)\n            result = conn.execute(\n                delete_query, {"tickers": tickers, "f_min": min_dt, "f_max": max_dt}\n            )\n            print(f"Deleted {result.rowcount} duplicate/old records.")\n\n        print(f"Inserting {len(df)} fresh records...", flush=True)\n        df.to_sql("market_data", con=engine, if_exists="append", index=False)\n\n        print("Daily intake completed.", flush=True)\n    else:\n        print("The market is closed or there is no new data today.", flush=True)\n\n\nwith DAG(\n    dag_id="daily_market_data_etl",\n    default_args=default_args,\n    description="Daily EOD data ingestion",\n    # 21:00 UTC post ny close\n    schedule="0 21 * * 1-5",\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=["ingestion", "daily", "market_data"],\n) as dag:\n    daily_task = PythonOperator(\n        task_id="run_daily_ingestion",\n        python_callable=fetch_daily_market_data,\n    )\n
64365319357247161	/opt/airflow/dags/light_retrain.py	2026-06-30 23:54:18.487791+00	from airflow.decorators import dag, task\nfrom datetime import datetime, timedelta\nimport sys\nimport logging\n\nsys.path.append("/opt/airflow") \nsys.path.append("/opt/airflow/quant_engine")\n\nfrom quant_engine.retrain_tasks import (\n    check_drift_and_metrics,\n    fetch_and_engineer_recent_data,\n    train_and_evaluate_challenger\n)\n\ndefault_args = {\n    'owner': 'quant_team',\n    'depends_on_past': False,\n    'email_on_failure': False,\n    'email_on_retry': False,\n    'retries': 1,\n    'retry_delay': timedelta(minutes=5),\n}\n\n@dag(\n    dag_id='etf_light_retrain_pipeline',\n    default_args=default_args,\n    description='Weekly Light Retrain: Drift detection, fixed-param retraining, and Champion vs Challenger validation.',\n    schedule_interval='0 2 * * 6',\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=['quant_engine', 'mlops', 'retrain'],\n)\ndef light_retrain_pipeline():\n\n    @task(task_id="check_drift_status")\n    def task_check_drift(**kwargs):\n        """\n        Analyzes the 'predictions_history' table to compute the Actionable Win Rate.\n        Raises an AirflowSkipException if performance remains above the alert threshold,\n        gracefully halting the DAG to prevent unnecessary retraining and structural overfitting.\n        """\n        logical_date_str = kwargs['ds']\n        logging.info(f"Analyzing Actionable Win Rate to evaluate concept drift up to {logical_date_str}...")\n        return check_drift_and_metrics(logical_date_str)\n\n    @task(task_id="extract_and_prep_recent_data")\n    def task_prep_data(**kwargs):\n        """\n        Retrieves an 18-month rolling window of raw market data up to the logical date.\n        Applies the TechnicalFeatureEngineer in training mode (is_inference=False) to preserve \n        the target variable and saves the engineered dataset as a temporary Parquet file.\n        """\n        logical_date_str = kwargs['ds']\n        logging.info(f"Extracting 18 months of historical data up to {logical_date_str}...")\n        return fetch_and_engineer_recent_data(logical_date_str)\n        \n    @task(task_id="arena_champion_vs_challenger")\n    def task_arena(data_path: str):\n        """\n        Trains a Challenger model with fixed hyperparameters and evaluates it against the \n        current production Champion over a blind hold-out test set. Promotes the Challenger \n        by overwriting the production artifact only if it achieves a higher Actionable Win Rate.\n        """\n        logging.info(f"Initiating validation duel (Champion vs Challenger) with data at: {data_path}")\n        return train_and_evaluate_challenger(data_path)\n\n    drift_status = task_check_drift()\n    training_data_path = task_prep_data()\n    \n    drift_status >> training_data_path\n    \n    promotion_result = task_arena(training_data_path)\n\ndag_instance = light_retrain_pipeline()
20517990476651668	/opt/airflow/dags/heavy_retrain_etl.py	2026-07-03 01:06:17.213178+00	from airflow.decorators import dag, task\nfrom datetime import datetime\nimport sys\nimport logging\n\nsys.path.append("/opt/airflow") \nsys.path.append("/opt/airflow/quant_engine")\n\nfrom quant_engine.heavy_retrain_tasks import (\n    extract_full_history,\n    select_top_features,\n    run_optuna_search,\n    promote_heavy_challenger\n)\n\ndefault_args = {\n    'owner': 'quant_team',\n    'depends_on_past': False,\n    'email_on_failure': True, \n    'retries': 0, \n}\n\n@dag(\n    dag_id='etf_heavy_retrain_pipeline',\n    default_args=default_args,\n    description='On-Demand Heavy Retrain: Feature Selection and Hyperparameter Bayesian Optimization.',\n    schedule_interval=None,\n    start_date=datetime(2024, 1, 1),\n    catchup=False,\n    tags=['quant_engine', 'mlops', 'optuna'],\n)\ndef heavy_retrain_pipeline():\n\n    @task(task_id="extract_full_history")\n    def task_extract_history(**kwargs):\n        logical_date_str = kwargs['ds']\n        logging.info(f"Extracting 4 years of history up to {logical_date_str}...")\n        return extract_full_history(logical_date_str)\n\n    @task(task_id="dynamic_feature_selection")\n    def task_feature_selection(data_path: str):\n        logging.info("Running automated feature selection (Top 15)...")\n        return select_top_features(data_path)\n\n    @task(task_id="run_optuna_search")\n    def task_optuna(data_path: str):\n        logging.info("Starting Bayesian Optimization (WFO)...")\n        return run_optuna_search(data_path)\n        \n    @task(task_id="arena_heavy_champion_vs_challenger")\n    def task_arena(data_path: str, selected_features: list, best_params: dict):\n        logging.info("Validating Optuna Challenger against current Champion...")\n        return promote_heavy_challenger(data_path, selected_features, best_params)\n\n    historical_data_path = task_extract_history()\n    features = task_feature_selection(historical_data_path)\n    optuna_params = task_optuna(historical_data_path)\n    \n    task_arena(historical_data_path, features, optuna_params)\n\nheavy_retrain = heavy_retrain_pipeline()
